// Build a rich summary of the per-department status for the email
const body = $input.first().json.body ?? $input.first().json;

const statut              = body.statut              ?? 'en_attente';
const departements_valides  = body.departements_valides  ?? [];
const departements_attente  = body.departements_en_attente ?? [];

const isValidated = statut === 'validee';
const subjectStatus = isValidated ? '✅ Validée' : '❌ Refusée';

// Build HTML list snippets used in the email template
const validesHtml = departements_valides.length
  ? departements_valides.map(d => `<li style="color:#16a34a;">✓ ${d}</li>`).join('')
  : '<li style="color:#94a3b8;">Aucun département validé pour l\'instant</li>';

const attenteHtml = departements_attente.length
  ? departements_attente.map(d => `<li style="color:#d97706;">⏳ ${d}</li>`).join('')
  : '';

return [{
  json: {
    ...body,
    is_validated: isValidated,
    subject_status: subjectStatus,
    valides_html: validesHtml,
    attente_html: attenteHtml
  }
}];

